import json
import ast

# Load data
reviews_2018 = locals()['var_function-call-3256252732933624935']
businesses = locals()['var_function-call-11923701340149909913']

# Get target business IDs
target_business_ids = set()
for r in reviews_2018:
    ref = r['business_ref']
    # Convert businessref_X to businessid_X
    if ref.startswith('businessref_'):
        bid = 'businessid_' + ref.split('_')[1]
        target_business_ids.add(bid)

# Function to check parking
def has_parking(attrs):
    if not attrs or attrs == 'None':
        return False

    # Check BikeParking
    if attrs.get('BikeParking') == 'True':
        return True

    # Check BusinessParking
    bp = attrs.get('BusinessParking')
    if bp:
        if bp == 'True':
            return True
        if bp.startswith('{'):
            try:
                bp_dict = ast.literal_eval(bp)
                # Check if any value is True
                for k, v in bp_dict.items():
                    if v is True:
                        return True
            except:
                pass
    return False

# Count
count = 0
found_businesses = []
for b in businesses:
    bid = b.get('business_id')
    if bid in target_business_ids:
        attrs = b.get('attributes')
        if has_parking(attrs):
            count += 1
            found_businesses.append(bid)

print("__RESULT__:")
print(count)

